// Sequential (slow) -- each waits for previous
async function sequential() {
  const a = await fetch('/api/a').then(r => r.json());
  const b = await fetch('/api/b').then(r => r.json());
  const c = await fetch('/api/c').then(r => r.json());
  return [a, b, c];
}

// Parallel (fast) -- all start simultaneously
async function parallel() {
  const [a, b, c] = await Promise.all([
    fetch('/api/a').then(r => r.json()),
    fetch('/api/b').then(r => r.json()),
    fetch('/api/c').then(r => r.json())
  ]);
  return [a, b, c];
}

// Race -- get the fastest response
async function raceExample() {
  const result = await Promise.race([
    fetch('/api/fast').then(r => r.json()),
    fetch('/api/backup').then(r => r.json())
  ]);
  return result;
}

async function* paginate(baseUrl, pageSize = 50) {
  let page = 1;
  let hasMore = true;

  while (hasMore) {
    const url = `${baseUrl}?page=${page}&limit=${pageSize}`;
    const res = await fetch(url);
    const data = await res.json();

    if (data.items.length === 0) hasMore = false;
    else {
      yield data.items;
      page++;
    }
  }
}

// Usage
(async () => {
  const pages = paginate('https://api.example.com/users');
  for await (const users of pages) {
    console.log(`Got ${users.length} users`);
  }
})();

async function fetchWithRetry(url, options = {}) {
  const { maxRetries = 3, baseDelay = 1000 } = options;

  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url);
      if (res.ok) return res;
      if (res.status < 500 && attempt < maxRetries) {
        throw new Error(`HTTP ${res.status}`);
      }
    } catch (err) {
      if (attempt === maxRetries) throw err;
      const delay = baseDelay * Math.pow(2, attempt - 1);
      console.log(`Retry ${attempt}/${maxRetries} after ${delay}ms`);
      await new Promise(r => setTimeout(r, delay));
    }
  }
}

await fetchWithRetry('https://api.example.com/data', {
  maxRetries: 5,
  baseDelay: 500
});

async function updateUsers(userIds) {
  const promises = userIds.map(id =>
    fetch(`/api/users/${id}`, { method: 'PATCH', body: JSON.stringify({ active: true }) })
      .then(res => ({ id, status: res.ok ? 'updated' : 'failed' }))
      .catch(() => ({ id, status: 'failed' }))
  );

  const results = await Promise.allSettled(promises);
  const succeeded = [];
  const failed = [];

  results.forEach(result => {
    if (result.status === 'fulfilled') {
      succeeded.push(result.value);
    } else {
      failed.push(result.reason);
    }
  });

  return { succeeded, failed };
}

async function fetchWithTimeout(url, timeoutMs = 5000) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await fetch(url, { signal: controller.signal });
    return response;
  } catch (err) {
    if (err.name === 'AbortError') {
      throw new Error(`Request timed out after ${timeoutMs}ms`);
    }
    throw err;
  } finally {
    clearTimeout(timeoutId);
  }
}

// Usage
try {
  const data = await fetchWithTimeout('https://api.example.com', 3000);
} catch (err) {
  console.error(err.message);
}
